// Objection Tracker: Webhook Ingest Handler
// Receives manual objection submissions via webhook
// Supports: LinkedIn exports, CRM exports, manual entry, CSV data

const webhookData = $input.first().json;

// Check if this is a batch import (array of items)
if (Array.isArray(webhookData.items) || Array.isArray(webhookData.data)) {
  // Route to batch processing
  return [{
    json: {
      ...webhookData,
      _route: 'batch'
    }
  }];
}

// Validate required fields for single item
const rawText = webhookData.text || webhookData.content || webhookData.raw_text || '';
const sourceName = webhookData.source_name || webhookData.source || 'manual_import';

if (!rawText || rawText.trim().length < 10) {
  return [{
    json: {
      success: false,
      error: 'Missing or invalid text content (minimum 10 characters)',
      received: webhookData,
      _route: 'error'
    }
  }];
}

// Determine source type from source_name or explicit type
function detectSourceType(name, explicitType) {
  if (explicitType) return explicitType;
  const lower = name.toLowerCase();
  if (lower.includes('linkedin')) return 'linkedin';
  if (lower.includes('call') || lower.includes('gong') || lower.includes('chorus')) return 'call_recording';
  if (lower.includes('chat') || lower.includes('intercom') || lower.includes('drift')) return 'chat';
  if (lower.includes('email')) return 'email';
  if (lower.includes('crm') || lower.includes('salesforce') || lower.includes('hubspot')) return 'crm';
  if (lower.includes('survey') || lower.includes('nps')) return 'survey';
  if (lower.includes('support') || lower.includes('zendesk') || lower.includes('ticket')) return 'support_ticket';
  return 'manual';
}

const sourceType = detectSourceType(sourceName, webhookData.source_type);

// Generate external ID if not provided
const externalId = webhookData.external_id ||
  webhookData.id ||
  `${sourceName.replace(/[^a-z0-9]/gi, '-').toLowerCase()}-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

// Parse date - accept various formats
function parseDate(dateInput) {
  if (!dateInput) return new Date().toISOString();
  if (typeof dateInput === 'string' && dateInput.includes('T')) return dateInput;
  const parsed = new Date(dateInput);
  if (!isNaN(parsed.getTime())) return parsed.toISOString();
  return new Date().toISOString();
}

// Build standardized item
const item = {
  external_id: externalId,
  raw_text: rawText.trim(),
  source_url: webhookData.url || webhookData.source_url || webhookData.link || null,
  source_author: webhookData.author || webhookData.source_author || webhookData.name || webhookData.contact || null,
  source_date: parseDate(webhookData.date || webhookData.source_date || webhookData.created_at),
  meta: {
    platform: sourceType,
    import_method: 'webhook',
    imported_at: new Date().toISOString(),
    ...(webhookData.meta || {}),
    company: webhookData.company || webhookData.organization || null,
    title: webhookData.title || webhookData.job_title || null,
    deal_stage: webhookData.deal_stage || webhookData.stage || null,
    deal_value: webhookData.deal_value || webhookData.amount || null,
    tags: webhookData.tags || [],
    connection_degree: webhookData.connection_degree || null,
    profile_url: webhookData.profile_url || webhookData.linkedin_url || null
  }
};

return [{
  json: {
    source_id: webhookData.source_id || null,
    source_name: sourceName,
    source_type: sourceType,
    items: [item],
    _route: 'single'
  }
}];

// Batch parser for CSV/JSON array imports
const input = $input.first().json;
const sourceName = input.source_name || 'batch_import';
const sourceType = input.source_type || 'manual';
const sourceId = input.source_id || null;

let rawItems = [];
if (Array.isArray(input.items)) rawItems = input.items;
else if (Array.isArray(input.data)) rawItems = input.data;

// Map fields to standard format
function mapToStandard(row) {
  const textFields = ['text', 'content', 'raw_text', 'message', 'body', 'note', 'notes', 'comment', 'feedback', 'objection', 'description'];
  let rawText = '';
  for (const field of textFields) {
    if (row[field]) { rawText = row[field]; break; }
  }

  const dateFields = ['date', 'created_at', 'created', 'timestamp', 'time', 'sent_date', 'received_date'];
  let sourceDate = null;
  for (const field of dateFields) {
    if (row[field]) { sourceDate = row[field]; break; }
  }

  const authorFields = ['author', 'name', 'from', 'sender', 'contact', 'first_name', 'full_name', 'customer', 'prospect'];
  let sourceAuthor = null;
  for (const field of authorFields) {
    if (row[field]) { sourceAuthor = row[field]; break; }
  }

  const urlFields = ['url', 'link', 'source_url', 'profile_url', 'linkedin_url'];
  let sourceUrl = null;
  for (const field of urlFields) {
    if (row[field]) { sourceUrl = row[field]; break; }
  }

  const externalId = row.id || row.external_id ||
    `${sourceName.replace(/[^a-z0-9]/gi, '-').toLowerCase()}-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

  return {
    external_id: externalId,
    raw_text: rawText,
    source_url: sourceUrl,
    source_author: sourceAuthor,
    source_date: sourceDate ? new Date(sourceDate).toISOString() : new Date().toISOString(),
    meta: {
      platform: sourceType,
      import_method: 'batch',
      imported_at: new Date().toISOString(),
      company: row.company || row.organization || row.account || null,
      title: row.title || row.job_title || row.position || null,
      deal_stage: row.deal_stage || row.stage || row.status || null
    }
  };
}

const items = [];
for (const row of rawItems) {
  const mapped = mapToStandard(row);
  if (mapped.raw_text && mapped.raw_text.trim().length >= 10) {
    items.push(mapped);
  }
}

return [{
  json: {
    source_id: sourceId,
    source_name: sourceName,
    source_type: sourceType,
    items: items,
    import_stats: { total_rows: rawItems.length, valid_items: items.length }
  }
}];

// Merge source_id with items and prepare for classification
const sourceResult = $('Upsert Source').first().json;
const itemsData = $('Merge Items').first().json;

const sourceId = itemsData.source_id || sourceResult.id;
const items = itemsData.items || [];

// Return each item individually for classification
return items.map(item => ({
  json: {
    source_id: sourceId,
    source_name: itemsData.source_name,
    source_type: itemsData.source_type,
    ...item
  }
}));

// Prepare for Anthropic classification
const item = $input.first().json;
const eventResult = $('Insert Events').first().json;

const prompt = `Analyze this customer feedback and classify any sales objections found.

Text to analyze:
"${item.raw_text}"

Respond with JSON:
{
  "has_objection": boolean,
  "objections": [
    {
      "category": "pricing|competition|timing|trust|features|integration|support|other",
      "summary": "brief summary",
      "verbatim": "exact quote if present",
      "severity": "low|medium|high",
      "sentiment": "negative|neutral|mixed"
    }
  ],
  "overall_sentiment": "positive|negative|neutral|mixed",
  "key_themes": ["theme1", "theme2"]
}`;

return [{
  json: {
    event_id: eventResult.id || item.event_id,
    source_id: item.source_id,
    source_name: item.source_name,
    raw_text: item.raw_text,
    prompt: prompt,
    meta: item.meta
  }
}];

// Parse Anthropic response and extract classification
const inputData = $('Prepare Classification Prompt').first().json;
const anthropicResponse = $input.first().json;

let classification = {
  has_objection: false,
  objections: [],
  overall_sentiment: 'neutral',
  key_themes: []
};

try {
  const content = anthropicResponse.content?.[0]?.text || '';
  // Extract JSON from response
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    classification = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  console.error('Failed to parse classification:', e);
}

return [{
  json: {
    event_id: inputData.event_id,
    source_id: inputData.source_id,
    source_name: inputData.source_name,
    raw_text: inputData.raw_text,
    classification: classification,
    has_objection: classification.has_objection || false,
    meta: inputData.meta
  }
}];

// Count results for response
const allItems = $('Prepare Items for Classification').all();
const classifiedItems = $('Parse Classification').all();
const objectionsFound = classifiedItems.filter(i => i.json.has_objection).length;

return [{
  json: {
    success: true,
    items_processed: allItems.length,
    objections_found: objectionsFound,
    timestamp: new Date().toISOString()
  }
}];
